357→    public function contextMore(Request $request): JsonResponse
358→    {
359→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
360→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
361→            return $this->responseJsonFail('无权限');
362→        }
363→        $messageId = $request->input('message_id');
364→        $offset = (int)$request->input('offset', 0);
365→        $limit = 5000;
366→
367→        // 校验消息归属：message → session → sfuser
368→        $msg = DB::table('daily_report_ai_messages as m')
369→            ->join('daily_report_ai_sessions as s', 's.id', '=', 'm.session_id')
370→            ->where('m.id', $messageId)
371→            ->where('m.role', 'context')
372→            ->where('s.sfuser_id', $sfuserId)
373→            ->whereNull('s.deleted_at')
374→            ->select('m.content')
375→            ->first();
376→
377→        if (!$msg) {
378→            return $this->responseJsonFail('消息不存在');
379→        }
380→
381→        $fullLength = mb_strlen($msg->content);
382→        $chunk = mb_substr($msg->content, $offset, $limit);
383→        $hasMore = ($offset + $limit) < $fullLength;
384→
385→        return $this->responseJsonSuccess([
386→            'content' => $chunk,
387→            'offset' => $offset,
388→            'has_more' => $hasMore,
389→            'full_length' => $fullLength,
390→        ]);
391→    }
