397→    public function saveMessages(Request $request): JsonResponse
398→    {
399→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
400→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
401→            return $this->responseJsonFail('无权限');
402→        }
403→
404→        $roleId = $request->input('role_id');
405→        $sessionId = $request->input('session_id');
406→        $messages = $request->input('messages', []);
407→
408→        if (empty($messages)) {
409→            return $this->responseJsonFail('消息不能为空');
410→        }
411→
412→        // 无 session 则创建
413→        if (!$sessionId) {
414→            $firstUserMsg = collect($messages)->firstWhere('role', 'user');
415→            $title = mb_substr($firstUserMsg['content'] ?? '新会话', 0, 20);
416→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
417→                'sfuser_id' => $sfuserId,
418→                'role_id' => $roleId,
419→                'title' => $title,
420→                'created_at' => now(),
421→                'updated_at' => now(),
422→            ]);
423→        } else {
424→            // 校验会话归属
425→            $session = DB::table('daily_report_ai_sessions')
426→                ->where('id', $sessionId)
427→                ->where('sfuser_id', $sfuserId)
428→                ->whereNull('deleted_at')
429→                ->first();
430→            if (!$session) {
431→                return $this->responseJsonFail('会话不存在');
432→            }
433→            DB::table('daily_report_ai_sessions')
434→                ->where('id', $sessionId)
435→                ->update(['updated_at' => now()]);
436→        }
437→
438→        // 批量插入消息
439→        $rows = [];
440→        foreach ($messages as $msg) {
441→            $role = $msg['role'] ?? '';
442→            if (!in_array($role, ['user', 'assistant', 'context'])) {
443→                continue;
444→            }
445→            $rows[] = [
446→                'session_id' => $sessionId,
447→                'role' => $role,
448→                'content' => $msg['content'] ?? '',
449→                'created_at' => now(),
450→            ];
451→        }
452→        if (!empty($rows)) {
453→            DB::table('daily_report_ai_messages')->insert($rows);
454→        }
455→
456→        return $this->responseJsonSuccess(['session_id' => $sessionId]);
457→    }
