459→    public function extractSlots(Request $request): JsonResponse
460→    {
461→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
462→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
463→            \Log::info('[lbl][0416-AI日报][AiSlots] 无权限', ['sfuser_id' => $sfuserId]);
464→            return $this->responseJsonFail('无权限');
465→        }
466→
467→        $message = $request->input('message');
468→        $conversationId = $request->input('conversation_id', '');
469→        $availableGroups = $request->input('available_groups', []);
470→        $availableMembers = $request->input('available_members', []);
471→        $previousContext = $request->input('previous_context');
472→        $hasExistingContext = $request->boolean('has_existing_context', false);
473→
474→        // 将可用分组和成员列表格式化为 prompt 中的列表
475→        $groupList = !empty($availableGroups)
476→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
477→            : '   - （无可用分组）';
478→        $memberList = !empty($availableMembers)
479→            ? implode('、', $availableMembers)
480→            : '（无可用成员列表）';
481→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
482→        $prevCtx = '无（首次查询）';
483→        if (!empty($previousContext)) {
484→            $prevMembers = implode('、', $previousContext['members'] ?? []);
485→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
486→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
487→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
488→        }
489→        $hasContextLabel = $hasExistingContext ? '是' : '否';
490→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
491→
492→        \Log::info('[lbl][0416-AI日报][AiSlots] request', [
493→            'sfuser_id' => $sfuserId,
